     9→
    10→export async function triggerBrowserActWorkflow(
    11→  workflowId: string,
    12→  callbackUrl: string,
    13→  apiKey?: string
    14→): Promise<{ taskId: string }> {
    15→  const key = apiKey || process.env.BROWSERACT_API_KEY;
    16→  if (!key) throw new Error("BrowserAct API key not configured");
    17→
    18→  const res = await fetch(`${BROWSERACT_API_BASE}/workflow/run-task`, {
    19→    method: "POST",
    20→    headers: {
    21→      "Authorization": `Bearer ${key}`,
    22→      "Content-Type": "application/json",
    23→    },
    24→    body: JSON.stringify({
    25→      workflow_id: workflowId,
    26→      callback_url: callbackUrl,
    27→    }),
    28→  });
    29→
    30→  if (!res.ok) {
    31→    const err = await res.text();
    32→    if (res.status === 429 || err.toLowerCase().includes("quota")) {
    33→      throw new Error("BROWSERACT_QUOTA_EXCEEDED");
    34→    }
    35→    throw new Error(`BrowserAct error ${res.status}: ${err}`);
    36→  }
    37→
    38→  const data = await res.json() as { task_id?: string; taskId?: string; id?: string };
    39→  return { taskId: data.task_id || data.taskId || data.id || "unknown" };
    40→}
    41→
    42→export async function getBrowserActTaskStatus(taskId: string, apiKey?: string): Promise<BrowserActTask> {
    43→  const key = apiKey || process.env.BROWSERACT_API_KEY;
    44→  if (!key) throw new Error("BrowserAct API key not configured");
    45→
    46→  const res = await fetch(`${BROWSERACT_API_BASE}/workflow/task/${taskId}`, {
    47→    headers: {
    48→      "Authorization": `Bearer ${key}`,
    49→    },
    50→  });
    51→
    52→  if (!res.ok) {
    53→    throw new Error(`BrowserAct status check failed: ${res.status}`);
    54→  }
    55→
    56→  const data = await res.json() as { status: string; task_id?: string };
    57→  return { taskId, status: data.status };
    58→}
