    95→async function triggerScrapeForSource(source: typeof sourcesTable.$inferSelect, urls: typeof sourceUrlsTable.$inferSelect[], req: any) {
    96→  const appBaseUrl = process.env.APP_BASE_URL || `https://${process.env.REPLIT_DEV_DOMAIN}`;
    97→  const taskIds: string[] = [];
    98→
    99→  for (const url of urls.filter(u => u.active)) {
   100→    const workflowId = url.browseractWorkflowId || source.browseractWorkflowId;
   101→
   102→    if (source.preferredScraper === "claude_fallback" || !workflowId) {
   103→      // Claude fallback - run inline
   104→      try {
   105→        const { events } = await claudeFetchAndExtract(url.url);
   106→        await processRawEvents(events as any[], source.id, "claude_fallback");
   107→        await db.update(sourcesTable).set({ lastScrapedAt: new Date() }).where(eq(sourcesTable.id, source.id));
   108→      } catch (err) {
   109→        await db.insert(errorLogsTable).values({
   110→          errorType: "scraping_error",
   111→          sourceId: source.id,
   112→          message: `Errore Claude fallback: ${String(err)}`,
   113→          context: { url: url.url },
   114→          resolved: false,
   115→        });
   116→      }
   117→    } else {
   118→      try {
   119→        const callbackUrl = `${appBaseUrl}/api/browseract/webhook/${source.id}/${url.id}`;
   120→        const { taskId } = await triggerBrowserActWorkflow(workflowId, callbackUrl);
   121→        taskIds.push(taskId);
   122→      } catch (err) {
   123→        const errMsg = String(err);
   124→        if (errMsg.includes("QUOTA_EXCEEDED")) {
   125→          await db.insert(errorLogsTable).values({
   126→            errorType: "browseract_quota",
   127→            sourceId: source.id,
   128→            message: "Crediti BrowserAct esauriti",
   129→            context: { url: url.url },
   130→            resolved: false,
   131→          });
   132→        } else {
   133→          await db.insert(errorLogsTable).values({
   134→            errorType: "browseract_error",
   135→            sourceId: source.id,
   136→            message: errMsg,
   137→            context: { url: url.url },
   138→            resolved: false,
   139→          });
   140→          // Fallback to Claude
   141→          try {
   142→            const { events } = await claudeFetchAndExtract(url.url);
   143→            await processRawEvents(events as any[], source.id, "claude_fallback");
   144→          } catch { /* ignore fallback errors */ }
   145→        }
   146→      }
   147→    }
   148→  }
   149→
   150→  await db.update(sourcesTable).set({ lastScrapedAt: new Date() }).where(eq(sourcesTable.id, source.id));
   151→  return taskIds;
   152→}
