   141→export async function processRawEvents(
   142→  rawEvents: RawEvent[],
   143→  sourceId: number,
   144→  scraper: "browseract" | "claude_fallback"
   145→): Promise<{ saved: number; errors: number }> {
   146→  let saved = 0;
   147→  let errors = 0;
   148→
   149→  for (const raw of rawEvents) {
   150→    try {
   151→      const title = raw.title?.trim();
   152→      if (!title) continue;
   153→
   154→      const dateStr = raw.date || raw.date_start || "";
   155→      let dateStart: Date | null = null;
   156→      let dateEnd: Date | null = null;
   157→      let dateParseConfidence: "high" | "medium" | "low" = "low";
   158→
   159→      if (dateStr) {
   160→        const parsed = parseItalianDate(dateStr);
   161→        dateStart = parsed.dateStart;
   162→        dateEnd = parsed.dateEnd;
   163→        dateParseConfidence = parsed.confidence;
   164→      }
   165→
   166→      if (raw.date_end) {
   167→        const parsedEnd = parseItalianDate(raw.date_end);
   168→        if (parsedEnd.dateStart) dateEnd = parsedEnd.dateStart;
   169→      }
   170→
   171→      if (!dateStart) {
   172→        await db.insert(errorLogsTable).values({
   173→          errorType: "no_date",
   174→          sourceId,
   175→          message: `Data non trovata per evento: ${title}`,
   176→          context: { raw },
   177→          resolved: false,
   178→        });
   179→        errors++;
   180→        continue;
   181→      }
   182→
   183→      const descriptionRaw = raw.description || raw.description_raw || "";
   184→      const dateDisplay = generateDateDisplay(dateStart, dateEnd);
   185→
   186→      // Deduplication check
   187→      const existingByUrl = raw.source_url
   188→        ? await db.select().from(eventsTable).where(eq(eventsTable.sourceUrl, raw.source_url)).limit(1)
   189→        : [];
   190→
   191→      if (existingByUrl.length > 0) {
   192→        const existing = existingByUrl[0];
   193→        await db.update(eventsTable).set({
   194→          title,
   195→          dateStart,
   196→          dateEnd,
   197→          dateDisplay,
   198→          dateParseConfidence,
   199→          descriptionRaw: descriptionRaw || existing.descriptionRaw,
   200→          location: raw.location || existing.location,
   201→          price: raw.price || existing.price,
   202→          category: raw.category || existing.category,
   203→          imageUrl: raw.image_url || existing.imageUrl,
   204→          updatedAt: new Date(),
   205→        }).where(eq(eventsTable.id, existing.id));
   206→        saved++;
   207→        continue;
   208→      }
   209→
   210→      const descriptionClean = descriptionRaw
   211→        ? await claudeRewrite(descriptionRaw, title, raw.location || null, dateDisplay).catch(() => descriptionRaw)
   212→        : "";
   213→
   214→      await db.insert(eventsTable).values({
   215→        sourceId,
   216→        title,
   217→        dateStart,
   218→        dateEnd,
   219→        dateDisplay,
   220→        dateParseConfidence,
   221→        recurring: false,
   222→        location: raw.location || null,
   223→        descriptionRaw: descriptionRaw || null,
   224→        descriptionClean: descriptionClean || null,
   225→        imageUrl: raw.image_url || null,
   226→        sourceUrl: raw.source_url || null,
   227→        category: raw.category || null,
   228→        price: raw.price || null,
   229→        status: "pending",
   230→        sourceType: "scraped",
   231→        scraper,
   232→      });
   233→
   234→      saved++;
   235→    } catch (err) {
   236→      errors++;
   237→      logger.error({ err, raw }, "Error processing raw event");
   238→      await db.insert(errorLogsTable).values({
   239→        errorType: "processing_error",
   240→        sourceId,
   241→        message: `Errore elaborazione evento: ${String(err)}`,
   242→        context: { raw: JSON.stringify(raw) },
   243→        resolved: false,
   244→      }).catch(() => {});
   245→    }
   246→  }
   247→
   248→  return { saved, errors };
   249→}
